import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"什刹海","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/shichahai.md","filePath":"landmarks/shichahai.md","lastUpdated":1784773307000}'),n={name:"landmarks/shichahai.md"};function d(s,t,i,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="什刹海" tabindex="-1">什刹海 <a class="header-anchor" href="#什刹海" aria-label="Permalink to &quot;什刹海&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-voV-byLj7qg?w=1200" alt="什刹海"></p><blockquote><p>&quot;柳荫深处是京华，一湖碧水映晚霞。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>什刹海位于北京市西城区，是北京城内面积最大、风貌保存最完整的一片历史街区。什刹海由前海、后海和西海（积水潭）三个相连的湖泊组成，周边分布着大量保存完好的胡同和四合院，是老北京风貌最集中的地区之一。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，尤以夏秋最佳</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6号线北海北站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区什刹海地区</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="形成与发展" tabindex="-1">形成与发展 <a class="header-anchor" href="#形成与发展" aria-label="Permalink to &quot;形成与发展&quot;">​</a></h3><p>什刹海地区在金代就已经形成湖泊。元代时，这里是京杭大运河的终点码头，也是当时世界上最繁华的商业区之一。</p><h4 id="元代" tabindex="-1">元代 <a class="header-anchor" href="#元代" aria-label="Permalink to &quot;元代&quot;">​</a></h4><p>元代定都北京（当时称大都），什刹海成为大运河的终点，商贾云集，舟楫往来，&quot;舳舻蔽水&quot;，极为繁华。</p><h4 id="明清时期" tabindex="-1">明清时期 <a class="header-anchor" href="#明清时期" aria-label="Permalink to &quot;明清时期&quot;">​</a></h4><p>明清时期，什刹海周边逐渐形成了众多王府、寺庙和民居。这里的胡同和四合院保存了大量老北京的风貌。</p><h3 id="近代变迁" tabindex="-1">近代变迁 <a class="header-anchor" href="#近代变迁" aria-label="Permalink to &quot;近代变迁&quot;">​</a></h3><p>20世纪90年代以来，什刹海地区进行了大规模的保护性修缮，成为北京最具特色的旅游区之一。</p><h2 id="主要区域" tabindex="-1">主要区域 <a class="header-anchor" href="#主要区域" aria-label="Permalink to &quot;主要区域&quot;">​</a></h2><h3 id="前海" tabindex="-1">前海 <a class="header-anchor" href="#前海" aria-label="Permalink to &quot;前海&quot;">​</a></h3><p>前海是什刹海最热闹的区域，周边酒吧、餐厅林立，是夜生活的聚集地。</p><h4 id="银锭桥" tabindex="-1">银锭桥 <a class="header-anchor" href="#银锭桥" aria-label="Permalink to &quot;银锭桥&quot;">​</a></h4><p>银锭桥是前海的标志性建筑，站在桥上可以远眺西山。桥名取自其形似倒置的银锭。</p><h3 id="后海" tabindex="-1">后海 <a class="header-anchor" href="#后海" aria-label="Permalink to &quot;后海&quot;">​</a></h3><p>后海相对安静，周边有许多名人故居和传统四合院。</p><h4 id="宋庆龄故居" tabindex="-1">宋庆龄故居 <a class="header-anchor" href="#宋庆龄故居" aria-label="Permalink to &quot;宋庆龄故居&quot;">​</a></h4><p>宋庆龄故居位于后海北沿，是一座保存完好的四合院。宋庆龄晚年在此居住。</p><h3 id="西海-积水潭" tabindex="-1">西海（积水潭） <a class="header-anchor" href="#西海-积水潭" aria-label="Permalink to &quot;西海（积水潭）&quot;">​</a></h3><p>西海最为安静，适合散步和休闲。周边有郭守敬纪念馆等景点。</p><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">特色</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>银锭桥</strong></td><td style="text-align:left;">前海地标</td><td style="text-align:left;">远眺西山</td></tr><tr><td style="text-align:left;"><strong>宋庆龄故居</strong></td><td style="text-align:left;">名人故居</td><td style="text-align:left;">了解宋庆龄生平</td></tr><tr><td style="text-align:left;"><strong>恭王府</strong></td><td style="text-align:left;">清代王府</td><td style="text-align:left;">和珅、恭亲王奕訢府邸</td></tr><tr><td style="text-align:left;"><strong>火神庙</strong></td><td style="text-align:left;">道教庙宇</td><td style="text-align:left;">祈求平安</td></tr><tr><td style="text-align:left;"><strong>烟袋斜街</strong></td><td style="text-align:left;">老北京商业街</td><td style="text-align:left;">购买纪念品</td></tr><tr><td style="text-align:left;"><strong>酒吧街</strong></td><td style="text-align:left;">夜生活</td><td style="text-align:left;">听音乐、品酒</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>半日游（胡同游）</strong>：</p><p>银锭桥 → 烟袋斜街 → 前海 → 恭王府 → 后海 → 宋庆龄故居</p><p><strong>一日游（深度游）</strong>：</p><p>上午：恭王府 → 前海 → 银锭桥 → 烟袋斜街 下午：后海 → 宋庆龄故居 → 西海 → 郭守敬纪念馆 晚上：后海酒吧街</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：傍晚时分景色最美，夕阳洒在湖面上，别有一番风味</li><li><strong>胡同游</strong>：建议租一辆人力三轮车，听老北京讲胡同故事</li><li><strong>酒吧消费</strong>：后海酒吧价格偏高，建议先问价再消费</li><li><strong>拍照位置</strong>：银锭桥、恭王府门前、后海湖边都是绝佳拍照点</li><li><strong>注意安全</strong>：夜间人流量大，注意保管好个人财物</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">6号线北海北站B口</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">5、13、42、107、111、118路北海站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;什刹海&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">恭王府</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">清代王府</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">俯瞰紫禁城</td></tr><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">网红胡同</td></tr><tr><td style="text-align:left;">钟鼓楼</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老北京地标</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>什刹海是老北京生活的缩影。在这里，你可以看到胡同里晾晒的衣服、巷子里下棋的老人、湖边垂钓的市民，感受到最地道的北京生活。</p><p>&quot;先有什刹海，后有北京城&quot;，这句话虽然有些夸张，但也说明了什刹海在北京历史上的重要地位。</p><hr><p>** 地址**：北京市西城区什刹海地区 <strong>🚇 地铁</strong>：6号线北海北站B口 <strong>📞 电话</strong>：010-83223327</p><p><strong>💡 Tips</strong>：什刹海的夜景非常迷人，建议傍晚前往，感受老北京的夜色。</p>',47)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
